package jnigen

import (
	"bytes"
	"fmt"
	"go/format"
	"os"
	"path/filepath"
	"strings"
	"text/template"
)

const (
	dirPerm  = 0o755
	filePerm = 0o644
)

// generatedHeader is prepended to all generated files. Split to avoid
// the clean target matching this source file.
var generatedHeader = "// Code generated by jnigen. DO NOT " + "EDIT.\n"

// Render executes templates with MergedSpec data and writes output files.
func Render(
	merged *MergedSpec,
	templatesDir string,
	outputDir string,
) error {
	funcMap := buildFuncMap()

	capiData := BuildCapiData(merged)

	// Define the template-to-output mapping and the data each template receives.
	type renderJob struct {
		templateName string
		outputPath   string
		data         any
		isHeader     bool // C header files skip gofmt
	}

	jobs := []renderJob{
		{
			templateName: "capi_vtable_dispatch.go.tmpl",
			outputPath:   filepath.Join(outputDir, "capi", "cgo_vtable_dispatch.h"),
			data:         capiData,
			isHeader:     true,
		},
		{
			templateName: "capi_functions.go.tmpl",
			outputPath:   filepath.Join(outputDir, "capi", "jni.go"),
			data:         capiData,
		},
		{
			templateName: "capi_const.go.tmpl",
			outputPath:   filepath.Join(outputDir, "capi", "const.go"),
			data:         capiData,
		},
		{
			templateName: "capi_jvalue_access.go.tmpl",
			outputPath:   filepath.Join(outputDir, "capi", "cgo_jvalue_access.go"),
			data:         capiData,
		},
	}

	// Add per-type capi files (one type per file).
	for _, tf := range buildCapiTypeFiles(capiData, outputDir) {
		jobs = append(jobs, renderJob{
			templateName: tf.templateName,
			outputPath:   tf.outputPath,
			data:         tf.data,
		})
	}

	// Add idiomatic layer render jobs.
	envData := BuildEnvData(merged)
	vmData := BuildVMData(merged)
	valueData := BuildValueData(merged)
	errorData := BuildErrorData(merged)
	typesData := BuildTypesData(merged)

	jobs = append(jobs,
		renderJob{
			templateName: "env.go.tmpl",
			outputPath:   filepath.Join(outputDir, "env.go"),
			data:         envData,
		},
		renderJob{
			templateName: "vm.go.tmpl",
			outputPath:   filepath.Join(outputDir, "vm.go"),
			data:         vmData,
		},
		renderJob{
			templateName: "jvalue.go.tmpl",
			outputPath:   filepath.Join(outputDir, "value.go"),
			data:         valueData,
		},
		renderJob{
			templateName: "errors.go.tmpl",
			outputPath:   filepath.Join(outputDir, "errors.go"),
			data:         errorData,
		},
		renderJob{
			templateName: "types.go.tmpl",
			outputPath:   filepath.Join(outputDir, "const.go"),
			data:         typesData,
		},
		renderJob{
			templateName: "method_id.go.tmpl",
			outputPath:   filepath.Join(outputDir, "method_id.go"),
			data:         nil,
		},
		renderJob{
			templateName: "field_id.go.tmpl",
			outputPath:   filepath.Join(outputDir, "field_id.go"),
			data:         nil,
		},
		renderJob{
			templateName: "object_ref_type.go.tmpl",
			outputPath:   filepath.Join(outputDir, "object_ref_type.go"),
			data:         nil,
		},
	)

	// Add per-type file render jobs.
	typeFiles := groupTypesByFile(merged, outputDir)
	for _, tf := range typeFiles {
		jobs = append(jobs, renderJob{
			templateName: "type_file.go.tmpl",
			outputPath:   tf.outputPath,
			data:         tf.data,
		})
	}

	// Load all templates.
	tmplFiles, err := filepath.Glob(filepath.Join(templatesDir, "*.go.tmpl"))
	if err != nil {
		return fmt.Errorf("listing templates: %w", err)
	}
	if len(tmplFiles) == 0 {
		return fmt.Errorf("no templates found in %s", templatesDir)
	}

	tmpl := template.New("").Funcs(funcMap)
	for _, f := range tmplFiles {
		data, readErr := os.ReadFile(f)
		if readErr != nil {
			return fmt.Errorf("reading template %s: %w", f, readErr)
		}
		name := filepath.Base(f)
		if _, parseErr := tmpl.New(name).Parse(string(data)); parseErr != nil {
			return fmt.Errorf("parsing template %s: %w", f, parseErr)
		}
	}

	// Execute each render job.
	for _, j := range jobs {
		if err := renderFile(tmpl, j.templateName, j.outputPath, j.data, j.isHeader); err != nil {
			return fmt.Errorf("rendering %s: %w", j.outputPath, err)
		}
	}

	return nil
}

func renderFile(
	tmpl *template.Template,
	name string,
	outputPath string,
	data any,
	isHeader bool,
) error {
	var buf bytes.Buffer

	if err := tmpl.ExecuteTemplate(&buf, name, data); err != nil {
		return fmt.Errorf("executing template %s: %w", name, err)
	}

	output := buf.Bytes()

	// Run gofmt on Go files.
	if !isHeader && strings.HasSuffix(outputPath, ".go") {
		formatted, err := format.Source(output)
		if err != nil {
			// Write the unformatted output for debugging.
			debugPath := outputPath + ".unformatted"
			_ = os.MkdirAll(filepath.Dir(debugPath), dirPerm)
			_ = os.WriteFile(debugPath, output, filePerm)
			return fmt.Errorf("formatting %s (unformatted saved to %s): %w",
				outputPath, debugPath, err)
		}
		output = formatted
	}

	if err := os.MkdirAll(filepath.Dir(outputPath), dirPerm); err != nil {
		return fmt.Errorf("creating directory for %s: %w", outputPath, err)
	}

	return os.WriteFile(outputPath, output, filePerm)
}

func buildFuncMap() template.FuncMap {
	return template.FuncMap{
		"camelCase":  camelCase,
		"lowerCamel": lowerCamel,
		"cTypeToGo":  cTypeToGo,
		"isVoid":     func(s string) bool { return s == "void" || s == "" },
		"join":       strings.Join,
		"trimSuffix": strings.TrimSuffix,
		"hasPrefix":  strings.HasPrefix,
		"hasSuffix":  strings.HasSuffix,
		"trimPrefix": strings.TrimPrefix,
		"upper":      strings.ToUpper,
		"lower":      strings.ToLower,
		"title":      strings.Title, //nolint:staticcheck // fine for code generation
		"add":        func(a, b int) int { return a + b },
		"sub":        func(a, b int) int { return a - b },
		"goParamName": func(cName string) string {
			// Convert C param names like "p0" to something reasonable.
			return cName
		},
		"capitalizeFirst": capitalizeFirst,
	}
}

func camelCase(s string) string {
	parts := strings.Split(s, "_")
	for i, p := range parts {
		parts[i] = capitalizeFirst(p)
	}
	return strings.Join(parts, "")
}

func lowerCamel(s string) string {
	cc := camelCase(s)
	if len(cc) == 0 {
		return cc
	}
	return strings.ToLower(cc[:1]) + cc[1:]
}

func capitalizeFirst(s string) string {
	if len(s) == 0 {
		return s
	}
	return strings.ToUpper(s[:1]) + s[1:]
}

type typeFileJob struct {
	outputPath string
	data       *TypeFileRenderData
}

func groupTypesByFile(merged *MergedSpec, outputDir string) []typeFileJob {
	groups := make(map[string][]*TypeRenderData)
	for _, rt := range merged.ReferenceTypes {
		fileName := typeFileNameFromGoType(rt.GoType)
		td := BuildTypeData(rt)
		groups[fileName] = append(groups[fileName], td)
	}

	var jobs []typeFileJob
	for fileName, types := range groups {
		jobs = append(jobs, typeFileJob{
			outputPath: filepath.Join(outputDir, fileName),
			data:       &TypeFileRenderData{Types: types},
		})
	}
	return jobs
}

func typeFileNameFromGoType(goType string) string {
	switch goType {
	case "String":
		return "string_jni.go"
	case "WeakRef":
		return "weakref.go"
	default:
		return strings.ToLower(goType) + ".go"
	}
}

type capiTypeFileJob struct {
	templateName string
	outputPath   string
	data         *CapiTypeFileRenderData
}

func buildCapiTypeFiles(
	capiData *CapiRenderData,
	outputDir string,
) []capiTypeFileJob {
	var jobs []capiTypeFileJob

	// Reference types: one file per type.
	for _, rt := range capiData.Types {
		entry := CapiTypeEntry{GoType: rt.GoType, CType: rt.CType}
		fileName := capiTypeFileName(rt.GoType)
		jobs = append(jobs, capiTypeFileJob{
			templateName: "capi_type_file.go.tmpl",
			outputPath:   filepath.Join(outputDir, "capi", fileName),
			data:         &CapiTypeFileRenderData{Types: []CapiTypeEntry{entry}},
		})
	}

	// Opaque types: one file per type.
	for _, ot := range capiData.OpaqueTypes {
		entry := CapiTypeEntry{GoType: ot.CapiType, CType: ot.CType}
		fileName := capiTypeFileName(ot.CapiType)
		jobs = append(jobs, capiTypeFileJob{
			templateName: "capi_type_file.go.tmpl",
			outputPath:   filepath.Join(outputDir, "capi", fileName),
			data:         &CapiTypeFileRenderData{Types: []CapiTypeEntry{entry}},
		})
	}

	// Hardcoded types: each in its own file.
	hardcoded := []CapiTypeEntry{
		{GoType: "Jvalue", CType: "jvalue"},
		{GoType: "Env", CType: "JNIEnv"},
		{GoType: "VM", CType: "JavaVM"},
		{GoType: "Cchar", CType: "char"},
		{GoType: "JNINativeMethod", CType: "JNINativeMethod"},
	}
	for _, entry := range hardcoded {
		fileName := capiTypeFileName(entry.GoType)
		jobs = append(jobs, capiTypeFileJob{
			templateName: "capi_type_file.go.tmpl",
			outputPath:   filepath.Join(outputDir, "capi", fileName),
			data:         &CapiTypeFileRenderData{Types: []CapiTypeEntry{entry}},
		})
	}

	// Primitives: one file per type.
	for _, p := range capiData.Primitives {
		goType := camelCase(p.CType)
		entry := CapiTypeEntry{GoType: goType, CType: p.CType}
		fileName := capiTypeFileName(goType)
		jobs = append(jobs, capiTypeFileJob{
			templateName: "capi_type_file.go.tmpl",
			outputPath:   filepath.Join(outputDir, "capi", fileName),
			data:         &CapiTypeFileRenderData{Types: []CapiTypeEntry{entry}},
		})
	}

	return jobs
}

func capiTypeFileName(goType string) string {
	return strings.ToLower(goType) + ".go"
}

// cTypeToGo converts a C type string to a Go capi type expression (C.xxx).
func cTypeToGo(cType string) string {
	// Handle pointer types.
	cType = strings.TrimSpace(cType)

	// Handle const qualifier.
	base := strings.TrimPrefix(cType, "const ")

	// Count and strip pointer/star suffixes.
	ptrCount := 0
	for strings.HasSuffix(base, "*") {
		base = strings.TrimSuffix(base, "*")
		base = strings.TrimSpace(base)
		ptrCount++
	}

	goBase := "C." + base

	// Special cases.
	switch base {
	case "void":
		if ptrCount == 0 {
			return ""
		}
		// void* → unsafe.Pointer, void** → *unsafe.Pointer, etc.
		result := "unsafe.Pointer"
		for range ptrCount - 1 {
			result = "*" + result
		}
		return result
	case "char":
		goBase = "C.char"
	}

	result := goBase
	for range ptrCount {
		result = "*" + result
	}
	return result
}
